| MCP:boP9fI | import request from '@/utils/request'
| MCP:boP9fI | 
| MCP:boP9fI | export function login(data) {
| MCP:boP9fI |   return request({
| MCP:boP9fI |     url: '/vue-admin-template/user/login',
| MCP:boP9fI |     method: 'post',
| MCP:boP9fI |     data,
| MCP:boP9fI |   })
| MCP:boP9fI | }
| MCP:boP9fI | 
| MCP:boP9fI | export function getInfo(token) {
| MCP:boP9fI |   return request({
| MCP:boP9fI |     url: '/vue-admin-template/user/info',
| MCP:boP9fI |     method: 'get',
| MCP:boP9fI |     params: { token },
| MCP:boP9fI |   })
| MCP:boP9fI | }
| MCP:boP9fI | 
| MCP:boP9fI | export function logout() {
| MCP:boP9fI |   return request({
| MCP:boP9fI |     url: '/vue-admin-template/user/logout',
| MCP:boP9fI |     method: 'post',
| MCP:boP9fI |   })
| MCP:boP9fI | }

| MCP:boP9fI | import Store from 'store'
| MCP:boP9fI | 
| MCP:boP9fI | const TokenKey = 'Admin-Token'
| MCP:boP9fI | 
| MCP:boP9fI | export function getToken() {
| MCP:boP9fI |   return Store.get(TokenKey)
| MCP:boP9fI | }
| MCP:boP9fI | 
| MCP:boP9fI | export function setToken(token) {
| MCP:boP9fI |   return Store.set(TokenKey, token)
| MCP:boP9fI | }
| MCP:boP9fI | 
| MCP:boP9fI | export function removeToken() {
| MCP:boP9fI |   return Store.remove(TokenKey)
| MCP:boP9fI | }

| MCP:boP9fI | const tokens = {
| MCP:boP9fI |   admin: {
| MCP:boP9fI |     token: 'admin-token',
| MCP:boP9fI |   },
| MCP:boP9fI |   editor: {
| MCP:boP9fI |     token: 'editor-token',
| MCP:boP9fI |   },
| MCP:boP9fI | }
| MCP:boP9fI | 
| MCP:boP9fI | const users = {
| MCP:boP9fI |   'admin-token': {
| MCP:boP9fI |     roles: ['admin'],
| MCP:boP9fI |     introduction: 'I am a super administrator',
| MCP:boP9fI |     avatar:
| MCP:boP9fI |       'https://wpimg.wallstcn.com/f778738c-e4f8-4870-b634-56703b4acafe.gif',
| MCP:boP9fI |     name: 'Super Admin',
| MCP:boP9fI |   },
| MCP:boP9fI |   'editor-token': {
| MCP:boP9fI |     roles: ['editor'],
| MCP:boP9fI |     introduction: 'I am an editor',
| MCP:boP9fI |     avatar:
| MCP:boP9fI |       'https://wpimg.wallstcn.com/f778738c-e4f8-4870-b634-56703b4acafe.gif',
| MCP:boP9fI |     name: 'Normal Editor',
| MCP:boP9fI |   },
| MCP:boP9fI | }
| MCP:boP9fI | 
| MCP:boP9fI | module.exports = [
| MCP:boP9fI |   // user login
| MCP:boP9fI |   {
| MCP:boP9fI |     url: '/vue-admin-template/user/login',
| MCP:boP9fI |     type: 'post',
| MCP:boP9fI |     response: (config) => {
| MCP:boP9fI |       const { username } = config.body
| MCP:boP9fI |       const token = tokens[username]
| MCP:boP9fI | 
| MCP:boP9fI |       // mock error
| MCP:boP9fI |       if (!token) {
| MCP:boP9fI |         return {
| MCP:boP9fI |           code: 60204,
| MCP:boP9fI |           message: 'Account and password are incorrect.',
| MCP:boP9fI |         }
| MCP:boP9fI |       }
| MCP:boP9fI | 
| MCP:boP9fI |       return {
| MCP:boP9fI |         code: 20000,
| MCP:boP9fI |         data: token,
| MCP:boP9fI |       }
| MCP:boP9fI |     },
| MCP:boP9fI |   },
| MCP:boP9fI | 
| MCP:boP9fI |   // get user info
| MCP:boP9fI |   {
| MCP:boP9fI |     url: '/vue-admin-template/user/info.*',
| MCP:boP9fI |     type: 'get',
| MCP:boP9fI |     response: (config) => {
| MCP:boP9fI |       const { token } = config.query
| MCP:boP9fI |       const info = users[token]
| MCP:boP9fI | 
| MCP:boP9fI |       // mock error
| MCP:boP9fI |       if (!info) {
| MCP:boP9fI |         return {
| MCP:boP9fI |           code: 50008,
| MCP:boP9fI |           message: 'Login failed, unable to get user details.',
| MCP:boP9fI |         }
| MCP:boP9fI |       }
| MCP:boP9fI | 
| MCP:boP9fI |       return {
| MCP:boP9fI |         code: 20000,
| MCP:boP9fI |         data: info,
| MCP:boP9fI |       }
| MCP:boP9fI |     },
| MCP:boP9fI |   },
| MCP:boP9fI | 
| MCP:boP9fI |   // user logout
| MCP:boP9fI |   {
| MCP:boP9fI |     url: '/vue-admin-template/user/logout',
| MCP:boP9fI |     type: 'post',
| MCP:boP9fI |     response: () => {
| MCP:boP9fI |       return {
| MCP:boP9fI |         code: 20000,
| MCP:boP9fI |         data: 'success',
| MCP:boP9fI |       }
| MCP:boP9fI |     },
| MCP:boP9fI |   },
| MCP:boP9fI | ]
